import{_ as e,a as t,b as l,c as r,d as i,e as s,f as n,g as o,h as p,i as d,j as h,k as c,l as m,m as g,n as u,o as b,p as w,q as _,r as C,s as q,t as f}from"./chunks/summary_privacy.C1wx2iF0.js";import{_ as k,o as M,c as v,af as O}from"./chunks/framework.BSym9njW.js";const R=JSON.parse('{"title":"🦞 OpenClaw - 全隐私本地 AI 智能体平台 AMD ROCm 版本","description":"","frontmatter":{},"headers":[],"relativePath":"zh/05-amd-yes/openclaw.md","filePath":"zh/05-amd-yes/openclaw.md","lastUpdated":1778402464000}'),x={name:"zh/05-amd-yes/openclaw.md"};function A(S,a,P,D,L,y){return M(),v("div",null,[...a[0]||(a[0]=[O('<h1 id="🦞-openclaw-全隐私本地-ai-智能体平台-amd-rocm-版本" tabindex="-1">🦞 OpenClaw - 全隐私本地 AI 智能体平台 AMD ROCm 版本 <a class="header-anchor" href="#🦞-openclaw-全隐私本地-ai-智能体平台-amd-rocm-版本" aria-label="Permalink to &quot;🦞 OpenClaw - 全隐私本地 AI 智能体平台 AMD ROCm 版本&quot;">​</a></h1><div align="center"><p><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/AMD-ROCm-ED1C24" alt="AMD"></a><a href="https://github.com/ValueCell-ai/ClawX" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/OpenClaw-Platform-orange" alt="OpenClaw"></a></p></div><p><strong>OpenClaw</strong> 是一个统一的消息处理与 AI 智能体平台，通过 Gateway（网关）将来自多种渠道（飞书、Telegram、iMessage、Slack 等）的用户消息汇聚到 Agent（智能体）进行处理，并运行在隔离的 Workspace（工作空间）中。该平台采用模块化设计，Agent 可以灵活调用各类工具与服务。</p><blockquote><p>OpenClaw (ClawX) 项目地址：<a href="https://github.com/ValueCell-ai/ClawX/releases" target="_blank" rel="noreferrer"><em>Link</em></a></p></blockquote><div align="center"><img src="'+e+'" alt="OpenClaw Logo" width="50%"></div><p><em><strong>接下来我将带领大家亲自动手，一步步在 AMD 395 Max AI PC 上完成 OpenClaw 的本地部署，打造完全隐私的个人 AI 助手！</strong></em></p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to &quot;项目亮点&quot;">​</a></h2><ul><li>🔒 <strong>完全隐私</strong>：本地大模型 + 本地 OpenClaw，所有数据不出本机</li><li>🦞 <strong>多渠道网关</strong>：飞书、Telegram、钉钉、Slack、iMessage 统一接入</li><li>🧠 <strong>Agent 架构</strong>：模块化设计，支持 memory、soul、skills 等上下文管理</li><li>🏠 <strong>本地部署</strong>：在 AMD 395 Max 上运行 35B 参数大模型，无需联网</li></ul><h2 id="openclaw-平台介绍" tabindex="-1">OpenClaw 平台介绍 <a class="header-anchor" href="#openclaw-平台介绍" aria-label="Permalink to &quot;OpenClaw 平台介绍&quot;">​</a></h2><p>OpenClaw 作为行业标杆，其全能的架构和&quot;操作系统终局&quot;的宏大愿景引发了 AI Agent 领域的现象级热潮。代码体量超过 43 万行，功能覆盖消息网关、Agent 运行时、工具调用、记忆管理等核心能力。</p><div align="center"><img src="'+t+'" alt="图5.6.1 OpenClaw 平台架构" width="90%"><p>图5.6.1 OpenClaw 平台架构</p></div><h3 id="生态对比" tabindex="-1">生态对比 <a class="header-anchor" href="#生态对比" aria-label="Permalink to &quot;生态对比&quot;">​</a></h3><p>OpenClaw 的成功也催生了社区衍生项目：</p><table tabindex="0"><thead><tr><th>项目</th><th>定位</th><th>特点</th></tr></thead><tbody><tr><td><strong>OpenClaw</strong></td><td>全能平台</td><td>43万行代码，操作系统级架构</td></tr><tr><td><strong>Nanobot</strong></td><td>极简主义</td><td>港大团队（HKUDS），轻量化方案</td></tr><tr><td><strong>PicoClaw</strong></td><td>边缘计算</td><td>Go 语言，单一二进制，极低资源占用</td></tr></tbody></table><div align="center"><img src="'+l+'" alt="图5.6.2 OpenClaw 生态对比" width="90%"><p>图5.6.2 OpenClaw 生态对比</p></div><h3 id="上下文占用" tabindex="-1">上下文占用 <a class="header-anchor" href="#上下文占用" aria-label="Permalink to &quot;上下文占用&quot;">​</a></h3><p>即使是新开一个对话，OpenClaw 也有 39K 上下文的占用——它会携带大量的 memory.md、soul.md、user.md 以及 skills 描述、工具描述等。OpenClaw 非常考验 Agent 的长上下文工具调用和规划能力，<strong>因此本地部署需要一个大显存机器！</strong></p><div align="center"><img src="'+r+'" alt="图5.6.3 OpenClaw 上下文占用" width="90%"><p>图5.6.3 OpenClaw 上下文占用（新对话即占 39K tokens）</p></div><h2 id="step-1-硬件准备-amd-395-max" tabindex="-1">Step 1: 硬件准备 - AMD 395 Max <a class="header-anchor" href="#step-1-硬件准备-amd-395-max" aria-label="Permalink to &quot;Step 1: 硬件准备 - AMD 395 Max&quot;">​</a></h2><p>AMD 395 Max 适合打游戏和做家庭 AI 中枢，模型性能和本地聊天内容的隐私性都可以得到保障。</p><div align="center"><img src="'+i+`" alt="图5.6.4 AMD 395 Max 规格" width="90%"><p>图5.6.4 AMD 395 Max 硬件规格</p></div><p>本文基础环境如下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>----------------</span></span>
<span class="line"><span>AMD Ryzen™ AI 9 HX 395 Max</span></span>
<span class="line"><span>LM Studio</span></span>
<span class="line"><span>Windows 11 / Linux</span></span>
<span class="line"><span>----------------</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><blockquote><p>本文默认学习者使用的是 AMD 395 Max AI PC 或其他搭载 AMD ROCm 支持的显卡设备。</p></blockquote><h2 id="step-2-lm-studio-部署本地模型" tabindex="-1">Step 2: LM Studio 部署本地模型 <a class="header-anchor" href="#step-2-lm-studio-部署本地模型" aria-label="Permalink to &quot;Step 2: LM Studio 部署本地模型&quot;">​</a></h2><p><a href="https://lmstudio.ai/" target="_blank" rel="noreferrer">LM Studio</a> 是一款专为本地运行大语言模型设计的跨平台桌面应用程序，支持 Windows、macOS 和 Linux 系统。它通过直观的图形界面让用户轻松搜索、下载并管理开源模型（如 GGUF 格式），无需联网即可在个人设备上实现离线对话、推理测试或启动 API 服务。</p><div align="center"><img src="`+s+'" alt="图5.6.5 LM Studio 界面" width="90%"><p>图5.6.5 LM Studio 界面</p></div><h3 id="_2-1-下载安装-lm-studio" tabindex="-1">2.1 下载安装 LM Studio <a class="header-anchor" href="#_2-1-下载安装-lm-studio" aria-label="Permalink to &quot;2.1 下载安装 LM Studio&quot;">​</a></h3><p>前往 <a href="https://lmstudio.ai/" target="_blank" rel="noreferrer">LM Studio 官网</a> 下载并安装。</p><h3 id="_2-2-加载推荐模型" tabindex="-1">2.2 加载推荐模型 <a class="header-anchor" href="#_2-2-加载推荐模型" aria-label="Permalink to &quot;2.2 加载推荐模型&quot;">​</a></h3><p>本教程推荐使用 <strong>gemma-4-26b-a4b</strong> 模型（MoE 架构，激活参数仅 4B，总参数 26B）。</p><p>在 LM Studio 中搜索并下载该模型的 GGUF 版本，加载完成后记录：</p><ul><li><strong>基础 URL</strong>：<code>http://127.0.0.1:12345/v1</code></li><li><strong>模型 ID</strong>：<code>gemma-4-26b-a4b</code></li></ul><blockquote><p>关于 LM Studio 详细配置，请参考 <a href="/hello-rocm/zh/01-deploy/">Getting Started with ROCm Deploy</a></p></blockquote><h2 id="step-3-安装-openclaw-clawx" tabindex="-1">Step 3: 安装 OpenClaw (ClawX) <a class="header-anchor" href="#step-3-安装-openclaw-clawx" aria-label="Permalink to &quot;Step 3: 安装 OpenClaw (ClawX)&quot;">​</a></h2><h3 id="_3-1-下载安装包" tabindex="-1">3.1 下载安装包 <a class="header-anchor" href="#_3-1-下载安装包" aria-label="Permalink to &quot;3.1 下载安装包&quot;">​</a></h3><p>打开 <a href="https://github.com/ValueCell-ai/ClawX/releases" target="_blank" rel="noreferrer">ClawX Release 页面</a>，选择适合你系统的安装包（Windows 或 Mac）。</p><div align="center"><img src="'+n+'" alt="图5.6.6 ClawX 下载页面" width="90%"><p>图5.6.6 ClawX Release 下载页面</p></div><h3 id="_3-2-安装-clawx" tabindex="-1">3.2 安装 ClawX <a class="header-anchor" href="#_3-2-安装-clawx" aria-label="Permalink to &quot;3.2 安装 ClawX&quot;">​</a></h3><p>双击安装包，仅为当前用户安装即可：</p><div align="center"><img src="'+o+'" alt="图5.6.7 安装 ClawX - 开始" width="45%"><img src="'+p+'" alt="图5.6.7 安装 ClawX - 用户选择" width="45%"><p>图5.6.7 双击安装，选择仅为当前用户安装</p></div><p>选择安装位置，等待安装完成：</p><div align="center"><img src="'+d+'" alt="图5.6.8 选择安装位置" width="45%"><img src="'+h+'" alt="图5.6.8 安装进行中" width="45%"><p>图5.6.8 选择安装位置并等待安装完成</p></div><h3 id="_3-3-初始化配置" tabindex="-1">3.3 初始化配置 <a class="header-anchor" href="#_3-3-初始化配置" aria-label="Permalink to &quot;3.3 初始化配置&quot;">​</a></h3><p>安装完成后点击运行，选择中文，然后点击下一步：</p><div align="center"><img src="'+c+'" alt="图5.6.9 选择语言" width="90%"><p>图5.6.9 选择中文并点击下一步</p></div><p>等待环境检查，缺少的环境它会指引你安装，然后点击下一步：</p><div align="center"><img src="'+m+'" alt="图5.6.10 环境检查" width="90%"><p>图5.6.10 环境检查（缺少的组件会自动引导安装）</p></div><h3 id="_3-4-配置本地模型" tabindex="-1">3.4 配置本地模型 <a class="header-anchor" href="#_3-4-配置本地模型" aria-label="Permalink to &quot;3.4 配置本地模型&quot;">​</a></h3><p>选择<strong>自定义本地部署的模型</strong>，使用 LM Studio 部署的 gemma-4-26b-a4b：</p><div align="center"><img src="'+g+'" alt="图5.6.11 模型配置 - 自定义" width="45%"><img src="'+u+'" alt="图5.6.11 模型配置 - 验证" width="45%"><p>图5.6.11 选择自定义模型并配置连接信息</p></div><p>填入以下配置：</p><table tabindex="0"><thead><tr><th>配置项</th><th>值</th></tr></thead><tbody><tr><td>基础 URL</td><td><code>http://127.0.0.1:12345/v1</code></td></tr><tr><td>模型 ID</td><td><code>gemma-4-26b-a4b</code></td></tr></tbody></table><p>验证保存后，点击下一步即完成全部安装：</p><div align="center"><img src="'+b+'" alt="图5.6.12 安装完成" width="90%"><p>图5.6.12 点击下一步，安装完成</p></div><h3 id="_3-5-安装成功" tabindex="-1">3.5 安装成功 <a class="header-anchor" href="#_3-5-安装成功" aria-label="Permalink to &quot;3.5 安装成功&quot;">​</a></h3><p>恭喜！一只纯本地的&quot;龙虾&quot;就安装好了 🦞</p><div align="center"><img src="'+w+'" alt="图5.6.13 OpenClaw 就绪" width="90%"><p>图5.6.13 本地 OpenClaw 安装成功</p></div><h2 id="step-4-使用-openclaw" tabindex="-1">Step 4: 使用 OpenClaw <a class="header-anchor" href="#step-4-使用-openclaw" aria-label="Permalink to &quot;Step 4: 使用 OpenClaw&quot;">​</a></h2><h3 id="_4-1-web-管理界面" tabindex="-1">4.1 Web 管理界面 <a class="header-anchor" href="#_4-1-web-管理界面" aria-label="Permalink to &quot;4.1 Web 管理界面&quot;">​</a></h3><p>点击左下角的&quot;OpenClaw 页面&quot;进入 Web 管理界面，这里可以聊天、管理 Agent，也可以在 ClawX 客户端直接聊天和管理：</p><div align="center"><img src="'+_+'" alt="图5.6.14 OpenClaw Web 界面" width="90%"><p>图5.6.14 OpenClaw Web 管理界面</p></div><h3 id="_4-2-配置消息频道" tabindex="-1">4.2 配置消息频道 <a class="header-anchor" href="#_4-2-配置消息频道" aria-label="Permalink to &quot;4.2 配置消息频道&quot;">​</a></h3><p>在频道设置中，可以一步一步配置飞书或钉钉等消息渠道，实现多平台消息统一接入：</p><div align="center"><img src="'+C+'" alt="图5.6.15 配置频道 - 飞书" width="45%"><img src="'+q+'" alt="图5.6.15 配置频道 - 钉钉" width="45%"><p>图5.6.15 配置飞书/钉钉消息频道</p></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><div align="center"><img src="'+f+'" alt="图5.6.16 全隐私方案" width="90%"><p>图5.6.16 本地部署大模型 + 本地部署 OpenClaw = 完全隐私的个人助手</p></div><p>通过本教程，你已经成功在 AMD 395 Max 上搭建了一套完全本地化的 AI 助手方案：</p><ul><li>✅ <strong>LM Studio</strong> 本地运行 gemma-4-26b-a4b 大模型</li><li>✅ <strong>OpenClaw (ClawX)</strong> 提供 Agent 平台和多渠道消息网关</li><li>✅ <strong>所有数据不出本机</strong>，隐私完全可控</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><details><summary>Q: 需要多大的显存才能运行？</summary><p>OpenClaw 新对话即占用 39K tokens 上下文，加上模型本身的参数，建议至少 24GB 显存。AMD 395 Max 的集成显存共享方案可以满足需求。</p></details><details><summary>Q: 支持哪些本地模型？</summary><p>任何兼容 OpenAI API 格式的本地模型均可使用，包括通过 LM Studio、Ollama、vLLM 等工具部署的模型。本教程推荐 gemma-4-26b-a4b（MoE 架构，实际激活参数仅 4B）。</p></details><details><summary>Q: 除了飞书和钉钉，还支持哪些消息渠道？</summary><p>OpenClaw 支持飞书、Telegram、iMessage、Slack、钉钉等多种消息平台，可在频道设置中按引导配置。</p></details><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://github.com/ValueCell-ai/ClawX/releases" target="_blank" rel="noreferrer">OpenClaw (ClawX) Release</a></li><li><a href="https://lmstudio.ai/" target="_blank" rel="noreferrer">LM Studio 官网</a></li><li><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer">ROCm 官方文档</a></li><li><a href="./../">hello-rocm 主项目</a></li></ul>',75)])])}const T=k(x,[["render",A]]);export{R as __pageData,T as default};
